UPDATE TB_MEMBER
SET PHONE       = #{phone},
    EMAIL       = #{email},
    MANAGER_NM  = #{managerNm},
    MANAGER_POS = #{managerPos}
WHERE MBR_SEQ = #{mbrSeq}

UPDATE TB_DONATION_PAYMENT
SET PAY_STATUS = #{payStatus},

    CANCEL_DT = NOW(), CANCEL_RSN = #{cancelRsn}


    REFUND_DT = NOW(), REFUND_RSN = #{refundRsn}

WHERE PAY_SEQ = #{paySeq}
